    87→// AlertSlice is a sortable slice of Alerts.
    88→type AlertSlice []*Alert
    89→
    90→func (as AlertSlice) Less(i, j int) bool {
    91→	// Look at labels.job, then labels.instance.
    92→	for _, overrideKey := range [...]model.LabelName{"job", "instance"} {
    93→		iVal, iOk := as[i].Labels[overrideKey]
    94→		jVal, jOk := as[j].Labels[overrideKey]
    95→		if !iOk && !jOk {
    96→			continue
    97→		}
    98→		if !iOk {
    99→			return false
   100→		}
   101→		if !jOk {
   102→			return true
   103→		}
   104→		if iVal != jVal {
   105→			return iVal < jVal
   106→		}
   107→	}
   108→	return as[i].Labels.Before(as[j].Labels)
   109→}
   110→func (as AlertSlice) Swap(i, j int) { as[i], as[j] = as[j], as[i] }
   111→func (as AlertSlice) Len() int      { return len(as) }
