   113→// Alerts turns a sequence of internal alerts into a list of
   114→// exposable model.Alert structures.
   115→func Alerts(alerts ...*Alert) model.Alerts {
   116→	res := make(model.Alerts, 0, len(alerts))
   117→	for _, a := range alerts {
   118→		v := a.Alert
   119→		// If the end timestamp is not reached yet, do not expose it.
   120→		if !a.Resolved() {
   121→			v.EndsAt = time.Time{}
   122→		}
   123→		res = append(res, &v)
   124→	}
   125→	return res
   126→}
